<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script>
<script>
function otrError(m){$('.isi_warning_delete').text(m||'Overtime Report gagal diproses.');$('.error_data_delete').fadeIn();}
function otrFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),employee_id:$('#filter_employee_id').val(),department_code:$('#filter_department_code').val(),cost_center_code:$('#filter_cost_center_code').val(),overtime_type:$('#filter_overtime_type').val(),overtime_status:$('#filter_overtime_status').val(),request_source:$('#filter_request_source').val(),impact_type:$('#filter_impact_type').val(),keyword:$('#filter_keyword').val()};}
function ajaxSel(s,act,ph){$(s).select2({width:'100%',allowClear:true,placeholder:ph,ajax:{url:'<?=base_admin();?>modul/overtime_report/overtime_report_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
$(function(){if($.fn.datepicker){$('.otr-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_overtime_type,#filter_overtime_status,#filter_request_source,#filter_impact_type').select2({width:'100%',allowClear:true});ajaxSel('#filter_employee_id','employee_search','Semua Employee');ajaxSel('#filter_department_code','department_search','Semua Department');ajaxSel('#filter_cost_center_code','cost_center_search','Semua Cost Center');}
var dt=$('#dtb_overtime_report').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{targets:[10],className:'text-right'},{width:'42px',targets:0},{width:'72px',targets:1}],ajax:{url:'<?=base_admin();?>modul/overtime_report/overtime_report_data.php',type:'post',data:function(d){$.extend(d,otrFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_requested').text(k.requested||0);$('#kpi_approved').text(k.approved||0);$('#kpi_posted').text(k.posted||0);$('#kpi_payable').text(k.payable_hours||0);$('#kpi_amount').text(k.amount||0);return j.data||[];},error:function(xhr){console.log(xhr.responseText);otrError('Data Overtime Report gagal dimuat.');}}});
$('#btn_filter_otr').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_otr').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_employee_id,#filter_department_code,#filter_cost_center_code,#filter_overtime_type,#filter_overtime_status,#filter_request_source,#filter_impact_type').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_otr').click(function(){window.location='<?=base_admin();?>modul/overtime_report/overtime_report_action.php?act=export&'+$.param(otrFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$(document).on('click','.btn-otr-detail',function(){$.post('<?=base_admin();?>modul/overtime_report/overtime_report_action.php?act=detail',{id:$(this).data('id')},function(h){$('#otr_detail_body').html(h);$('#modal_otr_detail').modal('show');});});
});
</script>
